INSERT INTO festivals_festival VALUES(1,'Hopla!','Belgium','Brussels','CIRCUS','','','2025-04-26','2025-05-02',0,'','late April–early May','Hopla! is a vibrant circus festival held in Brussels, Belgium. It features a variety of circus performances, street art, and music, celebrating the city''s rich cultural heritage. The festival aims to connect circus artists with the people of Brussels, fostering wonder, curiosity, and self-transcendence through various performances. Throughout the week, Hopla! brings shows to different neighborhoods in Brussels, while the weekend features performances in central locations such as Vismet, Place Sainte-Catherine, Place du Béguinage, and Square Marguerite Duras. The event is largely free, though some indoor performances may require reservations.','','','UNKNOWN','https://www.hopla.brussels/');
INSERT INTO festivals_festival VALUES(2,'Miramiro Summer Festival','Belgium','Ghent','STREET','steven@miramiro.be celine@miramiro.be','Celine Verkest / Steven De Jonge',NULL,NULL,1,replace(replace('Celine Verkest / \r\nSteven De Jonge','\r',char(13)),'\n',char(10)),'mid to late July','The Miramiro Summer Festival 2025 promises a spectacular edition filled with circus performances from the Ghent circus workshop, offering numerous shows for all ages. The festival will feature a variety of performances and entertainment, including music and circus acts, making it a vibrant and exciting event for attendees of all ages.',NULL,NULL,'UNKNOWN','https://miramiro.be/en/festival/circus-cravings/');
INSERT INTO festivals_festival VALUES(3,'Namur En Mai','Belgium','Namur','STREET','','','2025-05-23','2025-05-26',1,'nan','mid May','Namur en Mai is a vibrant street festival held annually in the city of Namur, Belgium. It features a variety of cultural performances, street art, music, and local cuisine, attracting visitors from all over the country and beyond. The festival includes acrobatics, juggling, dance, puppet shows, and a mix of traditional and innovative performances.',NULL,NULL,'UNKNOWN','https://namurenmai.org');
INSERT INTO festivals_festival VALUES(4,'Zomer Van Antwerpen','Belgium','Antwerp','STREET','programma@zva.be','','2025-08-22','2025-08-31',1,'nan','late June–late August','The Summer of Antwerp (Zomer van Antwerpen) is a vibrant street festival featuring theater, music, circus, and film performances in unexpected locations throughout the city. It includes a mix of local and international performances, with highlights such as ''Falstaff,'' ''Efectos Especiales,'' and ''The Conference of the Birds.'' The festival is accessible to all, with additional materials for wheelchair users and the deaf community.',NULL,NULL,'UNKNOWN','https://www.zva.be/2013/nl/programma/circus-zomerbar');
INSERT INTO festivals_festival VALUES(5,'Chassepierre','Belgium','Chassepierre','STREET','online','Nan',NULL,NULL,1,'nan','mid-August','The Chassepierre Festival is an annual International Festival of Street Arts that transforms the village of Chassepierre into a vibrant hub for street theater and circus performances. It features a diverse lineup of professional companies from the circus and street arts sectors, attracting artists and spectators from across Europe and beyond.',NULL,NULL,'UNKNOWN','https://www.chassepierre.be');
INSERT INTO festivals_festival VALUES(6,'Festival Up','Belgium','Brussels','CIRCUS','artistes@upupup.be','',NULL,NULL,1,'','late August','The Festival UP Belgium 2025 is part of the 31st season of UP – Circus & Performing Arts, which has been supporting contemporary circus for 26 years in Brussels, Belgium, and internationally. The festival includes various events and performances focused on circus arts and performing arts.','','','EMAIL','https://upupup.be/infos-pratiques/');
INSERT INTO festivals_festival VALUES(7,'La Piste Aux Espoirs','Belgium','Tournai','STREET','info@lapisteauxespoirs.com','',NULL,NULL,1,'nan','mid April','La Piste aux Espoirs is an international contemporary circus festival featuring a variety of performances, including street shows, innovative creations, and family-friendly activities. The festival collaborates with Maison de la Culture de Tournai and offers workshops, games, and networking opportunities for professionals and the public.',NULL,NULL,'UNKNOWN','http://www.lapisteauxespoirs.com/');
INSERT INTO festivals_festival VALUES(8,'BITEF Festival','Serbia','nan','STREET','Ksenija Đurović ksenija.djurovic@bitef.rs','nan',NULL,NULL,1,'nan','september',NULL,NULL,NULL,'UNKNOWN','https://festival.bitef.rs/en');
INSERT INTO festivals_festival VALUES(9,'Berlin Lacht','Germany','Berlin','STREET','info@berlin-lacht.de','Festival Organizer','2024-06-14','2024-06-16',0,NULL,'early August to mid-September','Berlin Lacht is an international street theater festival that brings together extraordinary artists from various nations to perform in Berlin. The festival features comedy acts, live music, and street performances, celebrating humor and entertainment in the heart of Berlin. The 2025 edition will take place at two main locations: Potsdamer Platz (August 5 to August 24) and Washingtonplatz (Berlin Hauptbahnhof) (August 26 to September 15).',NULL,NULL,'UNKNOWN','https://berlin-lacht.de');
INSERT INTO festivals_festival VALUES(10,'Sounddance Festival','Germany','Berlin','STREET','info@soundance-festival.de','',NULL,NULL,0,'Contemporary Dance','mid June','The Soundance Festival is known for its unique blend of dance, music, and text, offering a variety of performances that are choreographed, improvised, instrumental, live, or recorded. Each performance is distinct in its artistic style, making the festival a standout event for enthusiasts of contemporary dance and music.',NULL,NULL,'UNKNOWN','https://opencall.soundance-festival.de/');
INSERT INTO festivals_festival VALUES(11,'Artlake','Germany','Bad Schandau','STREET','booking@artlake-festival.de','Nan','2025-08-29','2025-09-01',0,'Weird','end of August','The Artlake Festival is an annual event held in Germany that combines music, art, and workshops. It is known for its diverse array of cultural activities and has become a favorite among music and art enthusiasts. The festival typically features live bands, DJs, workshops, and various forms of artistic expression, creating a vibrant and creative atmosphere. It is celebrated for its community spirit and the opportunity it provides for attendees to actively participate in various art forms. The festival is held in scenic locations, often near lakes, which adds to the overall experience.',NULL,NULL,'UNKNOWN','https://artlake-festival.de/');
INSERT INTO festivals_festival VALUES(12,'Theaterformen','Germany','Hannover','STREET','welcome@theaterformen.de','',NULL,NULL,1,'nan','mid–late June','The Theaterformen festival in Germany for 2025 features a variety of contemporary productions by international artists, including performances, lectures, documentaries, musicals, and choreographed excursions into nature. Notable performances include ''A Year Without Summer'' and ''Los días afuera / The days out there'' by Lola Arias. The festival also includes a Festival Campus Niedersachsen for students and emerging artists.',NULL,NULL,'UNKNOWN','https://www.theaterformen.de/news');
INSERT INTO festivals_festival VALUES(13,'Brighton Festival','United Kingdom','Brighton','OTHER','info@brightonfestival.org','',NULL,NULL,0,NULL,'May','The Brighton Festival in the United Kingdom for 2025 promises to be an exciting and diverse celebration of the arts, featuring a wide range of events across various art forms, including music, theatre, dance, circus, visual arts, film, literature, and debate. The festival will be curated by Grammy-nominated musician and composer Anoushka Shankar, inspired by the theme of ‘New Dawn’.',NULL,NULL,'UNKNOWN','https://brightonfestival.org');
INSERT INTO festivals_festival VALUES(14,'Spettacolo Brunnen','Switzerland','Brunnen','STREET','artist@spettacolo-brunnen.ch','',NULL,NULL,0,'not accepting','mid-August','The Spettacolo Brunnen is an international street artist festival held in Brunnen, Switzerland. This biennial event features over 50 street artists from around the world, transforming the Brunnen lakeside promenade into a vibrant cultural spectacle with performances and a food mile.',NULL,NULL,'UNKNOWN','https://spettacolo-brunnen.ch/');
INSERT INTO festivals_festival VALUES(15,'Artistic Dance Festival','Bulgaria','Sofia','STREET','info@antistaticfestival.org','',NULL,NULL,1,'nan','mid May','A contemporary dance and performance festival with a theme of ''Signs of Resistance.'' It aims to explore how movement can reframe boundaries and includes performances by various artists.',NULL,NULL,'UNKNOWN','http://antistaticfestival.org/en/');
INSERT INTO festivals_festival VALUES(16,'Mini Art Festival','Bulgaria','Nan','STREET','miniartfest@gmail.com','Nan',NULL,NULL,1,'Geo Kalev / Galina Ryom-Røjbek','June',NULL,NULL,NULL,'UNKNOWN','https://en.miniartfest.com/');
INSERT INTO festivals_festival VALUES(17,'Buskers Chur','Switzerland','Chur','STREET','info@buskers-chur.ch','Nan',NULL,NULL,1,'nan','early June','The Buskers Chur festival transforms the alpine city of Chur into a vibrant cultural hub under the open sky, featuring over 70 international artists from 20 different nations. The event offers a diverse program blending music, theater, circus acts, and artistic performances with more than 200 shows over two days. Attendees are encouraged to purchase a festival wristband and contribute ''hat money'' for the performances.',NULL,NULL,'UNKNOWN','https://buskers-chur.ch/info/');
INSERT INTO festivals_festival VALUES(18,'Copenhagen Circus Festival','Denmark','','STREET','sarah garde x-act@kittjohnson.dk','',NULL,NULL,1,'nan','','',NULL,NULL,'UNKNOWN','https://www.kittjohnson.dk/english/contact');
INSERT INTO festivals_festival VALUES(19,'Dynamo Circus Festival','Denmark','Odense','STREET','for residencies: gry@dynamoworkspace.dk open stage: gry@dynamoworkspace.dk','',NULL,NULL,1,'nan','mid June','The Dynamo Circus Festival in Denmark celebrates contemporary circus arts, featuring acrobatics, juggling, clowning, puppet shows, live performances, music, workshops, and film screenings. The festival includes events such as live concerts, open stage performances, and late-night afterparties. It also offers open circus training at the Circus Playground and a film competition called ''60secondscircusfilm''.',NULL,NULL,'UNKNOWN','https://dynamoworkspace.dk/festival/');
INSERT INTO festivals_festival VALUES(20,'Passage Festival','Denmark','nan','STREET','passagefestival@helsingor-teater.dk','nan',NULL,NULL,1,'nan','Juli',NULL,NULL,NULL,'UNKNOWN','https://passagefestival.nu/en/home/');
INSERT INTO festivals_festival VALUES(21,'Waves Festival','Denmark','Vordingborg','STREET','malco@cantabile2.dk','',NULL,NULL,1,'next 25','late August','A six-day event featuring a variety of performances including dance, contemporary circus, comedy, and visual performing arts. The festival hosts 19 performing arts companies from 13 different countries, making it one of Denmark''s largest curated international performing arts festivals.',NULL,NULL,'UNKNOWN','https://www.wavesfestival.dk/en/');
INSERT INTO festivals_festival VALUES(22,'Klp Festival','Germany','Mützingen','STREET','info@muetzingenta.de k.grasnick@gmx.de','','2025-05-15','2025-05-17',1,'nan','late May–early June','The KLP Festival is the largest self-organized cultural festival in Northern Germany, held annually between Ascension Day and Pentecost. It features live music, local food stalls, art exhibitions, and various cultural performances at multiple locations, including the Gasthof Meuchefitz.',NULL,NULL,'UNKNOWN','https://nan');
INSERT INTO festivals_festival VALUES(23,'Dance In The City - Festival Tanzende Stadt','Germany','','STREET','info@irene-k.be','',NULL,NULL,0,NULL,'','',NULL,NULL,'UNKNOWN','https://www.irene-k.be/');
INSERT INTO festivals_festival VALUES(24,'Bamberg','Germany','Bamberg','STREET','','',NULL,NULL,1,'nan','mid July','The ''Bamberg Zaubert'' festival is an annual event held in Bamberg, Germany, that transforms the historic city center into a vibrant stage for international street and variety performances. It features over 500 performances across approximately 20 stages, showcasing a diverse range of acts including magic, acrobatics, juggling, fire and light shows, and music. It attracts around 250,000 visitors each year and includes performances by over 100 international artists.',NULL,NULL,'UNKNOWN','http://www.bamberg-zaubert.de/');
INSERT INTO festivals_festival VALUES(25,'Düsseldorf Festival Full Spin','Germany','Düsseldorf','STREET','leoni@duesseldorf-festival.de','Nan',NULL,NULL,1,'nan','mid-September','The Düsseldorf Festival, which began in 1991 as Altstadtherbst, has grown into a significant event featuring a variety of performing arts including music, dance, theater, and new circus. The festival presents international productions and performances at various venues across the city, including Burgplatz.',NULL,NULL,'UNKNOWN','https://www.fullspinfestival.de/');
INSERT INTO festivals_festival VALUES(26,'Festival No Elephants - Freiburger Zirkustage','Germany','nan','STREET','ewerk@ewerk-freiburg.de','nan',NULL,NULL,1,'nan','nan',NULL,NULL,NULL,'UNKNOWN','https://ewerk-freiburg.de/programmatik/festivals-2/');
INSERT INTO festivals_festival VALUES(27,'Neuland Festival Winter Varieté','Germany','Oldenburg, Schortens, Cuxhaven','CIRCUS','mail@kultur-perspektiven.de','','2025-11-28','2025-12-07',1,'','late November–early December','The Neuland Winter-Varieté features a new program combining air acrobatics, artistry, juggling, humor, dance, and live singing, with performers from various countries including Japan, Germany, Italy, Denmark, Switzerland, France, and the USA. The show is approximately two hours long, including an intermission, and is suitable for all ages.','','','EMAIL','https://www.kultur-perspektiven.de');
INSERT INTO festivals_festival VALUES(28,'Freeman Festival','Germany','Munich','CIRCUS','info@wannda.de','','2025-09-13','2025-09-14',0,'','mid September','Festival for contemporary circus with various cultural events, workshops, and performances.','','','EMAIL','https://wannda.de/kontakt/');
INSERT INTO festivals_festival VALUES(29,'Brückensensationen Festival','Germany','Rheinfelden','STREET','kulturamt@rheinfelden-baden.de','',NULL,NULL,0,'nan','','The Brückensensationen Festival in Rheinfelden, Germany, is a vibrant street art festival that takes place annually. The festival is known for its unique setting around the old Rhine Bridge, which connects Switzerland and Germany, turning the area into a large open-air stage. The event features a variety of performances, including street theater, music, and other artistic displays, attracting around 12,000 visitors each year. The festival typically spans three days and includes numerous food and drink stalls, adding to the festive atmosphere.',NULL,NULL,'UNKNOWN','https://www.rheinfelden.de/brueckensensationen');
INSERT INTO festivals_festival VALUES(30,'Freiart Festival','Germany','Freiburg','STREET','info@freiartfestival.com','Nan',NULL,NULL,1,'DANCE','mid-September','The Frei Art Festival 2025 is an international dance and culture festival featuring performances, workshops, and seminars. It includes a variety of contemporary and urban dance sessions led by renowned artists, special events with short pieces by international choreographers, and residencies for selected artists.',NULL,NULL,'UNKNOWN','https://www.freiartfestival.com');
INSERT INTO festivals_festival VALUES(31,'Hut Festival','Germany','Nan','STREET','a.grimm@c3-chemnitz.de','Nan','2025-08-29','2025-08-31',1,'Anne Grimm','nan','The Hut Festival is a vibrant street festival held in Chemnitz, Germany. It features a variety of street performances, live music, local food stalls, and art exhibitions. The festival celebrates the cultural diversity and creativity of the region, attracting both locals and tourists.',NULL,NULL,'UNKNOWN','https://www.hutfestival.de/');
INSERT INTO festivals_festival VALUES(32,'Impulse Festival','Germany','Mülheim An Der Ruhr, Cologne, Düsseldorf','THEATRE','info@impulsefestival.de','Franziska Werner','2025-06-18','2025-07-06',1,'','late June–early July','A significant platform for independent theater in the German-speaking world, featuring showcase productions, the ''Post-West'' programming strand, and a range of discursive formats, workshops, and parties. The 2025 edition explores the theme ''Gottes Garten'' (God''s Garden) and examines aspects of a post-Western society.','','','EMAIL','https://www.impulsefestival.de');
INSERT INTO festivals_festival VALUES(33,'Outnow Festival','Germany','nan','STREET','https://outnowbremen.de/wp-content/uploads/2022/06/OUT23Ausschreibung_Form_DE.pdf','nan',NULL,NULL,1,'nan','nan',NULL,NULL,NULL,'UNKNOWN','https://outnowbremen.de/');
INSERT INTO festivals_festival VALUES(34,'Sommerpalast','Germany','nan','STREET','info@sommerpalast.de','nan',NULL,NULL,1,'nan','nan',NULL,NULL,NULL,'UNKNOWN','https://www.sommerpalast.de/');
INSERT INTO festivals_festival VALUES(35,'Palaisommer Dresden','Dresden','nan','STREET','polenz@palaissommer.de','nan',NULL,NULL,1,'nan','nan',NULL,NULL,NULL,'UNKNOWN','https://palaissommer.de/');
INSERT INTO festivals_festival VALUES(36,'Theater Op de Mark','Festival','nan','STREET','theateropdemarkt@limburg.be','nan',NULL,NULL,1,'nan','Okt/ Nov',NULL,NULL,NULL,'UNKNOWN','https://theateropdemarkt.be/');
INSERT INTO festivals_festival VALUES(37,'Viathea','Germany','Görlitz And Zgorzelec','STREET','viathea@g-h-t.de','Nan',NULL,NULL,1,'nan','end of June','The ViaThea Street Theater Festival is an international festival held annually in the cities of Görlitz and Zgorzelec. It transforms the streets and squares into an open-air stage, offering a diverse program of theater, dance, performance art, circus, and other art forms. The festival presents traditional and experimental theater and dance forms, performance art, contemporary circus, audio walks, and participatory projects in public spaces. It emphasizes togetherness, accessibility, and integration, with special accessibility information and a ''Rolli Podest'' supported by the ''Barrier-Free Construction'' investment program.',NULL,NULL,'UNKNOWN','https://viathea.de/kuenstler/');
INSERT INTO festivals_festival VALUES(38,'Lesliehof Graz','Austria','Graz','STREET','nan','Nan',NULL,NULL,0,'nan','August and December','The Lesliehof in Graz hosts several exciting events in 2025, including the Leslie Open Air Cinema from August 11 to 30, featuring international classics and Austrian films, and the Grazer ARTvent Markt, an advent market from November 28 to December 23, showcasing artisanal crafts and culinary delights.',NULL,NULL,'UNKNOWN','https://nan');
