INSERT INTO festivals_festival VALUES(42,'Kultursommerwien','Austria','Vienna','STREET','','','2025-06-26','2025-08-10',1,'','late June–early August','The Kultursommer Wien (Vienna Summer of Culture) transforms various locations across Vienna into open-air stages, offering a diverse program of free cultural events. The festival features cabaret, literature, music, dance, theater, and contemporary circus, with special offerings like family programs and participatory workshops. The 2025 edition runs under the motto ''Culture is where you are'' and includes over 2,000 artists and 500 acts across 28 venues in 17 districts.','','2025-12-01','FORM','');
