INSERT INTO festivals_festival VALUES(54,'Villach Festival','Austria','Villach','STREET','stadtmarketing@villach.at','','2025-07-01','2025-07-05',1,'','early July','The Villach Street Art Festival transforms the city center into a vibrant stage for approximately 100 international street artists from ten different nations. Attendees can expect a diverse program featuring jugglers, mimes, acrobats, musicians, comedians, and fire-eaters who perform as dusk settles. Performances will be held in various central locations, including Hauptplatz, Rathausplatz, and Kirchenplatz. The festival is free to attend, and artists typically rely on donations from the audience.','','','EMAIL','https://villach.at/stadt-erleben/kultur/strassenkunstfestival');
