INSERT INTO festivals_festival VALUES(59,'Olala Lienz','Austria','Lienz','STREET','info@ummigummi.at','Theresa And Elisa Mutschlechner','2025-07-22','2025-07-26',1,'hans mutschlechner','late July','An international street theater and circus festival held annually in Lienz, Austria. The festival features street art, acrobatics, comedy, juggling, interactive productions, music, and colorful walking acts. The 2025 edition includes a metaphysical circus performance and the Olala midday parade on Saturday.','','','EMAIL','http://www.olala.at/ueber-olala/');
INSERT INTO festivals_festival VALUES(60,'Linzer Pflasterspektakel','Austria','Linz','CIRCUS','pflasterspektakel@linz.at','','2025-07-17','2025-07-19',0,'','mid July','The Linzer Pflasterspektakel is an international street art festival featuring acrobatics, juggling, dance, comedy, clowning, pantomime, magic, figure and object theatre, high-wire and fire artistry, and music. Approximately 108 international artists and companies from 34 countries perform around 800 shows across 40 venues in the city center. Special features include the Kaleidoskop-Revue and musical nightlines in city center pubs, as well as a Children''s Spectacle with expanded activities in the Donaupark.','','','EMAIL','https://pflasterspektakel.at/de/');
