INSERT INTO festivals_festival VALUES(84,'Circusstad','Netherlands','Rotterdam','CIRCUS','menno@circusstad.nl','','2025-04-30','2025-05-04',0,'','late April–early May','Circusstad Rotterdam 2025 is a vibrant hub of contemporary circus arts featuring five days of spectacular performances, workshops, and interactive experiences. The festival blends traditional circus elements with modern artistic expressions like dance, theater, and music. Highlights include international acts, outdoor performances, and inclusive projects like ''Buitengewoon.'' The festival takes place at various locations across Rotterdam, including Schouwburgplein, Theater Rotterdam, and the old Luxor Theater.','','','EMAIL','https://circusstad.nl/');
