INSERT INTO festivals_festival VALUES(88,'Cirqu''Arau','Switzerland','Aarau','STREET','olgiati@cirquaarau.ch','Laura Olgiati',NULL,NULL,1,'Laura Olgiati','mid June','The Cirqu''Arau festival in Switzerland focuses on contemporary circus arts, featuring a variety of performances from small experimental forms to family shows. It takes place in various venues in Aarau, including the Alte Reithalle, museums, and tents.',NULL,NULL,'UNKNOWN','https://www.cirquaarau.ch');
