INSERT INTO festivals_festival VALUES(306,'“Aré ” Performing Arts Festival','Armenia','Yerevan','THEATRE','arecultural@gmail.com','','2025-05-03','2025-05-15',0,'','early–mid May','The ''ARé'' Performing Arts Festival, also known as ARé Fest 2025, is dedicated to exploring the dynamic intersections between performing and visual arts, embracing experimental and unconventional forms of expression. The festival''s program features performances, visual installations, discussions, and workshops across various venues in Yerevan. It aims to bring together international and local artists, foster global partnerships, and serve as a hub for creative exchange, showcasing Armenia''s contemporary art scene.','','','EMAIL','http://www.arepaf.am/');
INSERT INTO festivals_festival VALUES(307,'Athens Epidaurus Festival','Greece','Athens','THEATRE','artisticdirector@aefestival.gr','','2025-06-15','2025-08-30',0,'','late June–late August','The Athens Epidaurus Festival is one of Greece''s most significant cultural events, offering a diverse program of ancient Greek drama, music, contemporary dance, and interdisciplinary performances. It takes place at various venues including the Ancient Theatre of Epidaurus, the Little Theatre of Ancient Epidaurus, the Odeon of Herodes Atticus in Athens, and Peiraios 260.','','','EMAIL','http://aefestival.gr/?lang=en');
INSERT INTO festivals_festival VALUES(308,'Gauklerfestival','Germany','Attendorn','STREET','info@gauklerfestival.de','','2025-07-12','2025-07-13',0,'','mid July','The Attendorn Street Performers Festival transforms the town center into a stage for comedy, music, acrobatics, and interactive activities. It features international street artists and musicians, attracting thousands of visitors annually. The festival includes performances for children, families, and all ages, culminating in the awarding of the ''KleinKunstPreis''.','','','EMAIL','http://www.gauklerfest.de/');
INSERT INTO festivals_festival VALUES(309,'Tnt Festival Terrassa Noves Tendències','Spain','Terrassa','THEATRE','tnt@terrassa.cat','','2025-10-02','2025-10-04',0,'','early October','The TNT Festival Terrassa Noves Tendències is an 18th edition of the festival of live arts and new forms, dedicated to promoting and disseminating contemporary and multidisciplinary creation. It supports critical and committed artistic practices, embracing new artistic languages and exploring new ways of engaging with artistic expression. The festival addresses contemporary issues such as ecology, inequality, gender, diversity, and the dominance of new technologies.','','','EMAIL','http://tnt.cat/en/');
INSERT INTO festivals_festival VALUES(310,'Theaterfestival Basel','Switzerland','Basel','THEATRE','info@theaterfestival.ch','','2025-08-29','2025-08-31',0,'','late August','Theaterfestival Basel is a biennial event featuring various theater performances across multiple venues in Basel. The 2025 edition includes a collaboration with Kaserne Basel, taking place at the Kasernenareal and other partner theaters.','','','EMAIL','https://www.theaterfestival.ch/deplacement/');
INSERT INTO festivals_festival VALUES(311,'Feel Festival','Germany','Lichterfeld','MUSIC','kira@feel-festival.de','','2025-07-24','2025-07-27',0,'','late July','The Feel Festival at Berghaider See is a four-day cultural event featuring a diverse range of activities, including music, art, workshops, and discussions on topics such as sustainability and queer feminism. The festival offers karaoke, yoga sessions, saunas, and various light and art installations. Musically, it spans genres like electronic music, Indie, Rock, Punk, and Hip-hop.','','','EMAIL','https://feel-festival.de/kultur/');
INSERT INTO festivals_festival VALUES(312,'Buskers Bern','Switzerland','Bern','STREET','info@buskersbern.ch','','2025-08-06','2025-08-08',0,'','early August','The Buskers Bern Street Music Festival transforms the streets of Bern''s Old Town into a vibrant open-air festival. The 22nd edition features approximately 150 artists from around the world, showcasing music, dance, theatre, comedy, street performance, puppet theatre, art, and artistry. Around 70,000 visitors attend annually. Admission is free, but attendees can support the non-profit event by purchasing program booklets and festival wristbands.','','','EMAIL','https://www.buskersbern.ch/de');
