INSERT INTO festivals_festival VALUES(532,'Aufgetischt St.Gallen','Switzerland','St.Gallen','STREET','','','2025-05-09','2025-05-11',0,'','mid May','The largest street art festival in Eastern Switzerland, featuring over 100 artists from 26 nations presenting around 400 shows, including acrobatics, music, comedy, and dance, along with a diverse selection of street food.','','','UNKNOWN','https://www.aufgetischt.sg/');
INSERT INTO festivals_festival VALUES(533,'Asfaltart','Italy','Merano','STREET','','','2025-06-06','2025-06-08',0,'','early June','The Asfaltart International Street Art Festival transforms Merano into a vibrant open-air arena with over 200 performances by clowns, acrobats, dancers, fire-breathers, jugglers, tightrope walkers, and musicians from around the world. The festival includes events in Schenna and Dorf Tirol, with a parade, fire shows, high-wire acts, street theater, and culinary delights. It is a family-friendly event emphasizing sustainability as an official GreenEvent.','','','UNKNOWN','https://asfaltart.it/');
